SELECT Vendor.No_ AS VendorNo_, Vendor.Name AS VendorName, Item.[Trademark Code], Item.[Season Code], Item.[line code], Item.[collection code], Item.[product sex], Item.[product family], [VendutoCompratoProiezione-step10-Union].No_, Item.Description, Item.[Description 2], [VendutoCompratoProiezione-step10-Union].[Constant Variable Code] AS ColorCode, [Variable Code].Description AS Color, [VendutoCompratoProiezione-step10-Union].PairsSold, [VendutoCompratoProiezione-step10-Union].PairsPurchased, [VendutoCompratoProiezione-step10-Union].toBuy, [VendutoCompratoProiezione-step10-Union].toSell, [VendutoCompratoProiezione-step10-Union].ForecastedPairsByMarket_, [VendutoCompratoProiezione-step10-Union].ForecastedPairsByMarketCorrected_, [VendutoCompratoProiezione-step10-Union].toBuyByBudgetCorrected, [VendutoCompratoProiezione-step10-Union].toSellByBudgetCorrected, [VendutoCompratoProiezione-step10-Union].ForecastedPairsFlat, [VendutoCompratoProiezione-step10-Union].toBuyFlat, [VendutoCompratoProiezione-step10-Union].toSellFlat, [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].Incidenza, [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].[Bill-to Customer No_], [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].[Bill-to Name], [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].PairsSold_, Immagini.[Linked Document], DatiCarryOverESMU.[Potential Sold Out], DatiCarryOverESMU.[Sold Out], Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((((((Item RIGHT JOIN [VendutoCompratoProiezione-step10-Union] ON Item.No_ = [VendutoCompratoProiezione-step10-Union].No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente] ON ([VendutoCompratoProiezione-step10-Union].[Constant Variable Code] = [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].[Constant Variable Code]) AND ([VendutoCompratoProiezione-step10-Union].No_ = [VendutoCompratoProiezione-Vendite-step2-CalcoloIncidenzeCliente].No_)) LEFT JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) LEFT JOIN Immagini ON ([VendutoCompratoProiezione-step10-Union].[Constant Variable Code] = Immagini.[Constant Variable Code]) AND ([VendutoCompratoProiezione-step10-Union].No_ = Immagini.[Source No_])) LEFT JOIN DatiCarryOverESMU ON ([VendutoCompratoProiezione-step10-Union].[Constant Variable Code] = DatiCarryOverESMU.[Variable Code 01]) AND ([VendutoCompratoProiezione-step10-Union].No_ = DatiCarryOverESMU.[Model Item No_])) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_;

